19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	const COMPONENT_UNIT_PRICE = 25;
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const roundPremium = (amount: number): number => Math.ceil(amount);
27	
28	const priceForComponentCount = (count: number): number => {
29	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PRICE;
30	  return count * COMPONENT_UNIT_PRICE;
31	};
32	
33	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
34	  let total = 0;
35	  for (const count of componentCountsByType.values()) {
36	    total += priceForComponentCount(count);
37	  }
38	  return total;
39	};
