41	const baseForItems = (items: Item[]): number => {
42	  const componentCountsByType = new Map<string, number>();
43	  let nonComponentBase = 0;
44	  for (const item of items) {
45	    if (isComponent(item)) {
46	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
47	    } else {
48	      nonComponentBase += basePremiumFor(item);
49	    }
50	  }
51	  return nonComponentBase + sumComponentBase(componentCountsByType);
52	};
53	
54	const quotePremium = (items: Item[]): number => {
55	  const base = baseForItems(items);
56	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
57	  return roundPremium(base + firstInsuranceSurcharge + PROCESSING_FEE);
58	};
59	
60	export const runScenario = (input: {
61	  customer: { yearsWithMHPCO: number };
62	  steps: Step[];
63	}): { results: Result[] } => {
64	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
65	  return { results };
66	};
